class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode *prev = nullptr, *cur = head;
        while (cur) { auto* nxt = cur->next; cur->next = prev; prev = cur; cur = nxt; }
        return prev;
    }
};

